enum class ButtonState {
    Idle, Loading, Success
}

@Composable
fun MorphingButton(
    onClick: () -> Unit,
    state: ButtonState = ButtonState.valueOf("{$State_01}"),
    modifier: Modifier = Modifier,
    backgroundColor: Color = Color(android.graphics.Color.parseColor("{$BgColor_01}")),
    successColor: Color = Color(android.graphics.Color.parseColor("{$SuccessColor_01}")),
    cornerRadius: Dp = {$RadiusIdle_01}.dp,
    cornerRadiusResolved : Dp = {$RadiusResolved_01}.dp,
    text: String = "{$Text_01}",
    buttonWidthResolved : Dp = {$WidthResolved_01}.dp,
    buttonWidthIdle : Dp = {$WidthIdle_01}.dp,
    buttonHeight: Dp = {$Height_01}.dp
) {
    val buttonWidth by animateDpAsState(
        targetValue = if (state == ButtonState.Idle) buttonWidthIdle else buttonWidthResolved,
        label = "Button Width"
    )

    val buttonColor by animateColorAsState(
        targetValue = if (state == ButtonState.Success) successColor else backgroundColor,
        label = "Button Color"
    )

    val currentCornerRadius by animateDpAsState(
        targetValue = if (state == ButtonState.Idle) cornerRadius else cornerRadiusResolved,
        label = "Corner Radius"
    )

    Box(
        modifier = modifier
            .width(buttonWidth)
            .height( buttonHeight)
            .clip(RoundedCornerShape(currentCornerRadius))
            .background(buttonColor)
            .clickable(enabled = state == ButtonState.Idle, onClick = onClick),
        contentAlignment = Alignment.Center
    ) {
        AnimatedContent(
            targetState = state,
            transitionSpec = {
                fadeIn() togetherWith fadeOut()
            },
            label = "Button Content"
        ) { targetState ->
            when (targetState) {
                ButtonState.Idle -> {
                    Text(
                        text = text,
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge
                    )
                }
                ButtonState.Loading -> {
                    CircularProgressIndicator(
                        modifier = Modifier.size(24.dp),
                        color = Color.White,
                        strokeWidth = 3.dp
                    )
                }
                ButtonState.Success -> {
                    Icon(
                        imageVector = Icons.Default.Check,
                        contentDescription = "Success",
                        tint = Color.White,
                        modifier = Modifier.size(24.dp)
                    )
                }
            }
        }
    }
}

